{"content":"300: // SyncAlertmanagersForOrgs syncs configuration of the Alertmanager required by each organization.
301: func (moa *MultiOrgAlertmanager) SyncAlertmanagersForOrgs(ctx context.Context, orgIDs []int64) {
302: 	orgsFound := make(map[int64]struct{}, len(orgIDs))
303: 	dbConfigs, err := moa.getLatestConfigs(ctx)
304: 	if err != nil {
305: 		moa.logger.Error("Failed to load Alertmanager configurations", "error", err)
306: 		return
307: 	}
308: 	moa.alertmanagersMtx.Lock()
309: 	for _, orgID := range orgIDs {
310: 		if _, isDisabledOrg := moa.settings.UnifiedAlerting.DisabledOrgs[orgID]; isDisabledOrg {
311: 			moa.logger.Debug("Skipping syncing Alertmanager for disabled org", "org", orgID)
312: 			continue
313: 		}
314: 		orgsFound[orgID] = struct{}{}
315: 
316: 		alertmanager, found := moa.alertmanagers[orgID]
317: 
318: 		if !found {
319: 			// These metrics are not exported by Grafana and are mostly a placeholder.
320: 			// To export them, we need to translate the metrics from each individual registry and,
321: 			// then aggregate them on the main registry.
322: 			am, err := moa.factory(ctx, orgID)
323: 			if err != nil {
324: 				moa.logger.Error("Unable to create Alertmanager for org", "org", orgID, "error", err)
325: 				continue
326: 			}
327: 			moa.alertmanagers[orgID] = am
328: 			alertmanager = am
329: 		}
330: 
331: 		dbConfig, cfgFound := dbConfigs[orgID]
332: 		if !cfgFound {
333: 			if found {
334: 				// This means that the configuration is gone but the organization, as well as the Alertmanager, exists.
335: 				moa.logger.Warn("Alertmanager exists for org but the configuration is gone. Applying the default configuration", "org", orgID)
336: 			}
337: 			err := alertmanager.SaveAndApplyDefaultConfig(ctx)
338: 			if err != nil {
339: 				moa.logger.Error("Failed to apply the default Alertmanager configuration", "org", orgID)
340: 				continue
341: 			}
342: 			moa.alertmanagers[orgID] = alertmanager
343: 			continue
344: 		}
345: 
346: 		err := alertmanager.ApplyConfig(ctx, dbConfig)
347: 		if err != nil {
348: 			moa.logger.Error("Failed to apply Alertmanager config for org", "org", orgID, "id", dbConfig.ID, "error", err)
349: 			continue
350: 		}
351: 		moa.alertmanagers[orgID] = alertmanager
352: 	}
353: 
354: 	amsToStop := map[int64]Alertmanager{}
355: 	for orgId, am := range moa.alertmanagers {
356: 		if _, exists := orgsFound[orgId]; !exists {
357: 			amsToStop[orgId] = am
358: 			delete(moa.alertmanagers, orgId)
359: 			moa.metrics.RemoveOrgRegistry(orgId)
360: 		}
361: 	}
362: 	moa.metrics.ActiveConfigurations.Set(float64(len(moa.alertmanagers)))
363: 	moa.alertmanagersMtx.Unlock()
364: 
365: 	// Now, we can stop the Alertmanagers without having to hold a lock.
366: 	for orgID, am := range amsToStop {
367: 		moa.logger.Info("Stopping Alertmanager", "org", orgID)
368: 		am.StopAndWait()
369: 		moa.logger.Info("Stopped Alertmanager", "org", orgID)
370: 	}
371: 
372: 	moa.cleanupOrphanLocalOrgState(ctx, orgsFound)
373: }
374: 
375: // cleanupOrphanLocalOrgState will remove all orphaned nflog and silence states in kvstore by existing to currently
376: // active organizations. The original intention for this was the cleanup deleted orgs, that have had their states
377: // saved to the kvstore after deletion on instance shutdown.
378: func (moa *MultiOrgAlertmanager) cleanupOrphanLocalOrgState(ctx context.Context,
379: 	activeOrganizations map[int64]struct{},
380: ) {
381: 	storedFiles := []string{NotificationLogFilename, SilencesFilename}
382: 	for _, fileName := range storedFiles {
383: 		keys, err := moa.kvStore.Keys(ctx, kvstore.AllOrganizations, KVNamespace, fileName)
384: 		if err != nil {
385: 			moa.logger.Error("Failed to fetch items from kvstore", "error", err,
386: 				"namespace", KVNamespace, "key", fileName)
387: 		}
388: 		for _, key := range keys {
389: 			if _, exists := activeOrganizations[key.OrgId]; exists {
390: 				continue
391: 			}
392: 			err = moa.kvStore.Del(ctx, key.OrgId, key.Namespace, key.Key)
393: 			if err != nil {
394: 				moa.logger.Error("Failed to delete item from kvstore", "error", err,
395: 					"orgID", key.OrgId, "namespace", KVNamespace, "key", key.Key)
396: 			}
397: 		}
398: 	}
