249: func buildNotifierConfig(alertmanagers []ExternalAMcfg) (*config.Config, map[string]http.Header, error) {
250: 	amConfigs := make([]*config.AlertmanagerConfig, 0, len(alertmanagers))
251: 	headers := map[string]http.Header{}
252: 	for i, am := range alertmanagers {
253: 		u, err := url.Parse(am.URL)
254: 		if err != nil {
255: 			return nil, nil, err
256: 		}
257: 
258: 		sdConfig := discovery.Configs{
259: 			discovery.StaticConfig{
260: 				{
261: 					Targets: []model.LabelSet{{model.AddressLabel: model.LabelValue(u.Host)}},
262: 				},
263: 			},
264: 		}
265: 
266: 		timeout := am.Timeout
267: 		if timeout == 0 {
268: 			timeout = defaultTimeout
269: 		}
270: 
271: 		amConfig := &config.AlertmanagerConfig{
272: 			APIVersion:              config.AlertmanagerAPIVersionV2,
273: 			Scheme:                  u.Scheme,
274: 			PathPrefix:              u.Path,
275: 			Timeout:                 model.Duration(timeout),
276: 			ServiceDiscoveryConfigs: sdConfig,
277: 		}
278: 
279: 		if am.Headers != nil {
280: 			// The key has the same format as the AlertmanagerConfigs.ToMap() would generate
281: 			// so we can use it later on when working with the alertmanager config map.
282: 			headers[fmt.Sprintf("config-%d", i)] = am.Headers
283: 		}
284: 
285: 		// Check the URL for basic authentication information first
286: 		if u.User != nil {
287: 			amConfig.HTTPClientConfig.BasicAuth = &common_config.BasicAuth{
288: 				Username: u.User.Username(),
289: 			}
290: 
291: 			if password, isSet := u.User.Password(); isSet {
292: 				amConfig.HTTPClientConfig.BasicAuth.Password = common_config.Secret(password)
293: 			}
294: 		}
295: 		amConfigs = append(amConfigs, amConfig)
296: 	}
297: 
298: 	notifierConfig := &config.Config{
299: 		AlertingConfig: config.AlertingConfig{
300: 			AlertmanagerConfigs: amConfigs,
301: 		},
302: 	}
303: 
304: 	return notifierConfig, headers, nil
305: }
